# Tests for `deep_get`

```python
import pytest

from mymodule import deep_get  # adjust import to your module


class TestDeepGetHappyPath:
    """Tests for typical, expected usage."""

    def test_single_key(self):
        assert deep_get({"a": 1}, "a") == 1

    def test_two_level_nested(self):
        assert deep_get({"a": {"b": 2}}, "a.b") == 2

    def test_deeply_nested(self):
        d = {"a": {"b": {"c": {"d": "found"}}}}
        assert deep_get(d, "a.b.c.d") == "found"

    def test_returns_dict_value(self):
        d = {"a": {"b": {"c": 1}}}
        assert deep_get(d, "a.b") == {"c": 1}

    def test_returns_list_value(self):
        d = {"a": {"b": [1, 2, 3]}}
        assert deep_get(d, "a.b") == [1, 2, 3]

    def test_returns_none_value_explicitly_set(self):
        # If the value really is None, it should return None (not the default).
        # NOTE: Due to .get(key, default), None values yield None — works as expected here
        # because default is None. Documented for clarity.
        d = {"a": {"b": None}}
        assert deep_get(d, "a.b") is None


class TestDeepGetEdgeCases:
    """Tests for edge cases."""

    def test_empty_dict_returns_default(self):
        assert deep_get({}, "a") is None

    def test_empty_dict_with_custom_default(self):
        assert deep_get({}, "a", default="missing") == "missing"

    def test_missing_top_level_key(self):
        assert deep_get({"a": 1}, "b") is None

    def test_missing_nested_key(self):
        assert deep_get({"a": {"b": 1}}, "a.c") is None

    def test_missing_nested_key_custom_default(self):
        assert deep_get({"a": {"b": 1}}, "a.c", default="x") == "x"

    def test_path_extends_beyond_non_dict_value(self):
        # 'a.b' is an int, can't traverse into it
        assert deep_get({"a": {"b": 5}}, "a.b.c") is None

    def test_path_extends_beyond_non_dict_with_default(self):
        assert deep_get({"a": {"b": 5}}, "a.b.c", default="fallback") == "fallback"

    def test_path_through_list_returns_default(self):
        # Lists are not dicts; traversal should stop and return default
        assert deep_get({"a": [1, 2, 3]}, "a.b", default="x") == "x"

    def test_falsy_values_returned_correctly(self):
        d = {"a": {"b": 0, "c": "", "d": False, "e": []}}
        assert deep_get(d, "a.b") == 0
        assert deep_get(d, "a.c") == ""
        assert deep_get(d, "a.d") is False
        assert deep_get(d, "a.e") == []

    def test_default_can_be_any_type(self):
        assert deep_get({}, "a", default=[1, 2]) == [1, 2]
        assert deep_get({}, "a", default={"x": 1}) == {"x": 1}
        assert deep_get({}, "a", default=42) == 42

    def test_numeric_string_keys(self):
        d = {"1": {"2": "value"}}
        assert deep_get(d, "1.2") == "value"

    def test_keys_with_spaces(self):
        d = {"a key": {"b key": "value"}}
        # No space-splitting; only dot-splitting
        assert deep_get(d, "a key.b key") == "value"

    def test_single_empty_string_key(self):
        # 'keys.split('.')' on '' yields [''], so it looks up key ''
        d = {"": "empty-key-value"}
        assert deep_get(d, "") == "empty-key-value"

    def test_empty_string_key_missing(self):
        assert deep_get({"a": 1}, "") is None


class TestDeepGetErrorCases:
    """Tests for invalid inputs that raise exceptions."""

    def test_none_keys_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            deep_get({"a": 1}, None)

    def test_non_string_keys_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            deep_get({"a": 1}, 123)

    def test_non_dict_top_level_returns_default(self):
        # Passing a non-dict as `d` — first iteration sees non-dict, returns default
        assert deep_get("not a dict", "a") is None
        assert deep_get([1, 2, 3], "a", default="x") == "x"
        assert deep_get(None, "a", default="x") == "x"

    def test_unhashable_default_still_returned(self):
        sentinel = object()
        result = deep_get({}, "missing", default=sentinel)
        assert result is sentinel


